#include <bits/stdc++.h>
using namespace std;

int a[10][10]; // 数独棋盘，1-9行，1-9列

// 检查在(x,y)位置放置数字val是否合法
bool is_valid(int x, int y, int val) {
    // 检查同一行是否有重复
    for (int j = 1; j <= 9; j++) {
        if (a[x][j] == val) return false;
    }

    // 检查同一列是否有重复
    for (int i = 1; i <= 9; i++) {
        if (a[i][y] == val) return false;
    }

    // 检查所在3x3小方格是否有重复
    int block_x = (x - 1) / 3 + 1; // 1-3
    int block_y = (y - 1) / 3 + 1; // 1-3

    for (int i = (block_x - 1) * 3 + 1; i <= block_x * 3; i++) {
        for (int j = (block_y - 1) * 3 + 1; j <= block_y * 3; j++) {
            if (a[i][j] == val) return false;
        }
    }

    return true;
}

// 回溯法求解数独
bool dfs(int x, int y) {
    // 如果已经处理完所有单元格，求解成功
    if (x > 9) return true;

    // 计算下一个单元格的位置
    int next_x, next_y;
    if (y == 9) {
        next_x = x + 1;
        next_y = 1;
    } else {
        next_x = x;
        next_y = y + 1;
    }

    // 如果当前单元格已有数字，直接处理下一个
    if (a[x][y] != 0) {
        return dfs(next_x, next_y);
    }

    // 尝试填入1-9的数字
    for (int val = 1; val <= 9; val++) {
        if (is_valid(x, y, val)) {
            a[x][y] = val; // 尝试填入数字
            if (dfs(next_x, next_y)) { // 递归处理下一个单元格
                return true; // 如果成功，返回true
            }
            a[x][y] = 0; // 回溯，恢复为空
        }
    }

    return false; // 没有合适的数字，返回false
}

int main() {
    // 读取数独初始状态，0表示待填充的空格
    for (int i = 1; i <= 9; i++) {
        for (int j = 1; j <= 9; j++) {
            cin >> a[i][j];
        }
    }

    // 求解数独
    if (dfs(1, 1)) {
        // 输出求解结果
        for (int i = 1; i <= 9; i++) {
            for (int j = 1; j <= 9; j++) {
                cout << a[i][j] << " ";
            }
            cout << endl;
        }
    } else {
        cout << "该数独无解" << endl;
    }

    return 0;
}
